// Build the Gemini prompt for structured resume extraction
const resumeText = $input.first().json.body.resume_text || '';

if (!resumeText.trim()) {
  throw new Error('resume_text is required in the request body');
}

const schema = JSON.stringify({
  contact: {
    name: 'string',
    email: 'string',
    phone: 'string',
    linkedin: 'string',
    github: 'string'
  },
  summary: 'string',
  skills: [
    { category: 'string', items: ['string'] }
  ],
  experience: [
    {
      company: 'string',
      title: 'string',
      dates: 'string',
      bullets: ['string']
    }
  ],
  projects: [
    {
      name: 'string',
      tech: ['string'],
      bullets: ['string']
    }
  ],
  education: [
    {
      institution: 'string',
      degree: 'string',
      dates: 'string',
      gpa: 'string'
    }
  ]
}, null, 2);

const prompt = `You are a precise resume data extraction assistant.

Extract all information from the resume text below and return it as a single valid JSON object matching this schema exactly:

${schema}

Rules:
- Return ONLY valid JSON. No markdown fences, no explanation text, no trailing commas.
- Do not invent information not present in the source text.
- If a field is not present in the resume, use an empty string "" for string fields or an empty array [] for array fields.
- For the skills array, group skills into logical categories (e.g., "Languages", "Frameworks", "Tools", "Cloud").
- For experience bullets, preserve the original phrasing but clean up formatting.
- The gpa field should be a string (e.g., "3.8/4.0") or empty string if not mentioned.

RESUME TEXT:
---
${resumeText}
---

Return the JSON object now:`;

return [{ json: { prompt } }];

// Parse the JSON string returned by Gemini into a structured object
const response = $input.first().json;

// Navigate the Gemini response envelope
let rawText;
try {
  rawText = response.candidates[0].content.parts[0].text;
} catch (e) {
  throw new Error('Unexpected Gemini response structure: ' + JSON.stringify(response));
}

// Strip any accidental markdown fences Gemini may include
const cleaned = rawText
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/\s*```$/i, '')
  .trim();

let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (e) {
  throw new Error('Failed to parse Gemini JSON response: ' + e.message + '\nRaw text: ' + rawText);
}

// Ensure all top-level keys exist with safe defaults
const result = {
  contact: parsed.contact || { name: '', email: '', phone: '', linkedin: '', github: '' },
  summary: parsed.summary || '',
  skills: Array.isArray(parsed.skills) ? parsed.skills : [],
  experience: Array.isArray(parsed.experience) ? parsed.experience : [],
  projects: Array.isArray(parsed.projects) ? parsed.projects : [],
  education: Array.isArray(parsed.education) ? parsed.education : []
};

return [{ json: result }];
